@namespace sv_63d44cdfd26248829b217828d72cd59e.Components.JobApplication

<div class="step-indicator d-flex align-items-start justify-content-between mb-4">
    @for (int i = 0; i < _stepNames.Length; i++)
    {
        var step = i;
        var isCompleted = step < CurrentStep;
        var isCurrent = step == CurrentStep;
        var cssClass = isCompleted ? "completed" : isCurrent ? "active" : "future";

        @if (step > 0)
        {
            <div class="step-connector @(isCompleted ? "completed" : "")"></div>
        }

        <div class="step-item @cssClass"
             @onclick="() => OnStepClick(step)"
             role="@(isCompleted ? "button" : "")"
             style="@(isCompleted ? "cursor:pointer" : "")">
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <div class="step-label">@_stepNames[step]</div>
        </div>
    }
</div>

@code {
    private static readonly string[] _stepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

@namespace sv_63d44cdfd26248829b217828d72cd59e.Components.JobApplication
@using sv_63d44cdfd26248829b217828d72cd59e.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Reference @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name *</label>
                <input class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
