@namespace sv_63d44cdfd26248829b217828d72cd59e.Components.JobApplication
@using sv_63d44cdfd26248829b217828d72cd59e.Models

<div class="step-content">
    <h4 class="mb-4">Review Your Application</h4>

    @if (IsSubmitted)
    {
        <div class="alert alert-success text-center py-4">
            <h5 class="mb-2">&#10003; Application Submitted Successfully!</h5>
            <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                    <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                    <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                    <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
                </div>
            </div>
        </div>

        <!-- Work History -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-3 pb-3 border-bottom last-no-border">
                        <div><strong>@entry.Title</strong> at @entry.Company</div>
                        <div class="text-muted">
                            @entry.StartDate?.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </div>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <div class="mt-1">@entry.Description</div>
                        }
                    </div>
                }
            </div>
        </div>

        <!-- References -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var r in References)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <span class="text-muted">@r.Email &middot; @r.Phone</span>
                    </div>
                }
            </div>
        </div>

        <!-- Cover Letter -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Cover Letter</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@CoverLetter</p>
            </div>
        </div>

        @if (submitError is not null)
        {
            <div class="alert alert-danger">@submitError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Submit Application
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }

    private bool isSubmitting;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

@namespace sv_63d44cdfd26248829b217828d72cd59e.Components.JobApplication

<div class="step-indicator d-flex align-items-start justify-content-between mb-4">
    @for (int i = 0; i < _stepNames.Length; i++)
    {
        var step = i;
        var isCompleted = step < CurrentStep;
        var isCurrent = step == CurrentStep;
        var cssClass = isCompleted ? "completed" : isCurrent ? "active" : "future";

        @if (step > 0)
        {
            <div class="step-connector @(isCompleted ? "completed" : "")"></div>
        }

        <div class="step-item @cssClass"
             @onclick="() => OnStepClick(step)"
             role="@(isCompleted ? "button" : "")"
             style="@(isCompleted ? "cursor:pointer" : "")">
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <div class="step-label">@_stepNames[step]</div>
        </div>
    }
</div>

@code {
    private static readonly string[] _stepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

