@namespace sv_63d44cdfd26248829b217828d72cd59e.Components.JobApplication
@using sv_63d44cdfd26248829b217828d72cd59e.Models

<div class="step-content">
    <h4 class="mb-3">Personal Information</h4>

    <div class="mb-3">
        <label class="form-label">Full Name *</label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email *</label>
        <input type="email" class="form-control @(emailError is not null ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (emailError is not null)
        {
            <div class="invalid-feedback">@emailError</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone *</label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Address *</label>
        <textarea class="form-control" @bind="Model.Address" @bind:event="oninput" rows="2"></textarea>
    </div>

    @if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <div class="d-flex justify-content-end">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Next
        </button>
    </div>
</div>

@code {
    [Parameter] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            validationError = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var isValid = await ValidateEmail(Model.Email);
            if (!isValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            isValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

