@namespace sv_63d44cdfd26248829b217828d72cd59e.Components.JobApplication

<div class="step-content">
    <h4 class="mb-3">Cover Letter</h4>

    <div class="mb-2">
        <textarea class="form-control" rows="12"
                  @bind="CoverLetter" @bind:event="oninput"
                  @bind:after="NotifyChanged"
                  maxlength="@MaxLength"
                  placeholder="Write your cover letter here..."></textarea>
    </div>

    <div class="text-muted text-end mb-3">
        @CoverLetter.Length / @MaxLength characters
    </div>

    @if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        validationError = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            validationError = "Please write a cover letter.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

