@page "/apply"
@rendermode InteractiveServer

@using sv_63d44cdfd26248829b217828d72cd59e.Components.JobApplication
@using sv_63d44cdfd26248829b217828d72cd59e.Models
@using sv_63d44cdfd26248829b217828d72cd59e.Services

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnStepSelected="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personal"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep Personal="personal"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        OnEdit="GoToStep"
                        OnBack="PreviousStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep;
    private bool isSubmitted;
    private int? applicationId;

    // Form state
    private PersonalInfoModel personal = new();
    private List<WorkEntryModel> workEntries = new() { new() };
    private List<ReferenceModel> references = new() { new(), new() };
    private string coverLetter = "";

    private void NextStep() => currentStep++;
    private void PreviousStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(personal.FullName, personal.Email, personal.Phone, personal.Address),
            new WorkHistory(workEntries.Select(w => new WorkEntry(
                w.Company,
                w.Title,
                w.StartDate ?? DateTime.MinValue,
                w.IsCurrent ? null : w.EndDate,
                w.Description)).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitted = true;
    }
}

/* Step Indicator */
.step-indicator {
    gap: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 0 0 auto;
    min-width: 80px;
}

.step-connector {
    flex: 1 1 auto;
    height: 2px;
    background-color: #dee2e6;
    margin-top: 18px;
    min-width: 20px;
}

.step-connector.completed {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    border: 2px solid #dee2e6;
    background-color: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step-label {
    font-size: 0.75rem;
    margin-top: 4px;
    text-align: center;
    color: #6c757d;
    white-space: nowrap;
}

/* Active step */
.step-item.active .step-circle {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

/* Completed step */
.step-item.completed .step-circle {
    border-color: #198754;
    background-color: #198754;
    color: #fff;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.completed:hover .step-circle {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
}

/* Future step */
.step-item.future .step-circle {
    opacity: 0.5;
}

.step-item.future .step-label {
    opacity: 0.5;
}

/* Step content area */
.step-content {
    min-height: 300px;
}

/* Remove bottom border from last child in review cards */
::deep .last-no-border:last-child {
    border-bottom: none !important;
    margin-bottom: 0 !important;
    padding-bottom: 0 !important;
}

